"""
_generate_fixtures.py — Script to generate all 90+ paper attribution fixtures.
[!] Run once to populate fixture directory. Not imported by tests.
"""
import json
import os

MARKERS = {
    "test_fixture": True,
    "demo_only": True,
    "paper_only": True,
    "research_only": True,
    "not_live": True,
    "no_broker": True,
    "no_real_account": True,
    "no_real_orders": True,
    "not_for_production": True,
    "paper_attribution_only": True,
}

BASE_DIR = os.path.dirname(os.path.abspath(__file__))


def fx(fixture_id, purpose, category, **extra):
    data = {
        "fixture_id": fixture_id,
        "purpose": purpose,
        "schema_version": "167",
        "policy_version": "1.6.7-paper-attribution",
        "category": category,
        **MARKERS,
        **extra,
    }
    path = os.path.join(BASE_DIR, f"{fixture_id}.json")
    with open(path, "w") as f:
        json.dump(data, f, indent=2, sort_keys=True)
    return fixture_id


